// Parse Phase 2 Instructions for Database Creation
const phase2Instructions = $json.phase2Instructions;
const phase2Context = $('Setup Phase 2 Context').first().json.phase2Context;

// Get categorized ideas from the instructions
const categorizedIdeas = phase2Instructions.categorized_ideas || [];
const targetDatabases = phase2Instructions.target_databases || {};

// Build instruction text for the Notion Agent
let instructionText = '# PHASE 2: DATABASE ITEM CREATION\n\n';
instructionText += '## OBJECTIVE\n';
instructionText += 'Create database items from categorized ideas using the validated database endpoints.\n\n';

instructionText += '## TARGET DATABASES\n';
Object.entries(targetDatabases).forEach(([type, id]) => {
  const count = categorizedIdeas.filter(idea => idea.categorization.database === type).length;
  instructionText += `- **${type.toUpperCase()}**: ${id} (${count} items)\n`;
});
instructionText += '\n';

instructionText += '## CATEGORIZED IDEAS TO CREATE\n';
categorizedIdeas.forEach((idea, index) => {
  instructionText += `### ${index + 1}. ${idea.title}\n`;
  instructionText += `- Database: ${idea.categorization.database}\n`;
  instructionText += `- Database ID: ${idea.categorization.database_id}\n`;
  instructionText += `- Category: ${idea.categorization.category}\n`;
  instructionText += `- Priority: ${idea.categorization.priority}\n`;
  instructionText += `- Tags: ${idea.categorization.tags.join(', ')}\n`;
  instructionText += `- Content: ${idea.original_content}\n\n`;
});

instructionText += '## EXECUTION STEPS\n';
instructionText += '1. For each idea, create a new page in the target database\n';
instructionText += '2. Use POST /api/databases/{database_id}/pages\n';
instructionText += '3. Include rich content formatting\n';
instructionText += '4. Set appropriate properties based on categorization\n\n';

instructionText += '**BEGIN DATABASE CREATION NOW**\n';

// Return properly formatted data for n8n
return {
  json: {
    instructionText: instructionText,
    task_id: 'phase2_database_creation',
    phase: 'database_creation',
    categorized_ideas: categorizedIdeas,
    target_databases: targetDatabases,
    context_id: phase2Context.mockPhase1Results.context_id,
    operation_mode: phase2Instructions.operation_mode
  }
};

// Direct Database Creation - Phase 2 Implementation
const phase2Instructions = $json;
const categorizedIdeas = phase2Instructions.categorized_ideas || [];
const targetDatabases = phase2Instructions.target_databases || {};

// Process each categorized idea and create database items
const creationResults = [];
let totalProcessed = 0;
let successfulCreations = 0;
let failedCreations = 0;

// Mock database creation for testing (replace with actual API calls)
categorizedIdeas.forEach((idea, index) => {
  totalProcessed++;

  try {
    // Simulate database item creation
    const databaseId = idea.categorization.database_id;
    const databaseType = idea.categorization.database;

    // Create properties based on database type
    let properties = {};
    let content = idea.original_content;

    if (databaseType === 'projects') {
      properties = {
        "Name": {
          "title": [{
            "text": { "content": idea.title }
          }]
        },
        "Tags": {
          "multi_select": idea.categorization.tags.map(tag => ({ "name": tag }))
        }
      };
      content = `# ${idea.title}\n\n${idea.original_content}\n\n## Project Details\n- **Category**: ${idea.categorization.category}\n- **Priority**: ${idea.categorization.priority}\n- **Tags**: ${idea.categorization.tags.join(', ')}`;
    } else if (databaseType === 'knowledge') {
      properties = {
        "Title": {
          "title": [{
            "text": { "content": idea.title }
          }]
        },
        "Tags": {
          "multi_select": idea.categorization.tags.map(tag => ({ "name": tag }))
        }
      };
      content = `# ${idea.title}\n\n${idea.original_content}\n\n## Knowledge Base Entry\n- **Category**: ${idea.categorization.category}\n- **Tags**: ${idea.categorization.tags.join(', ')}`;
    } else if (databaseType === 'journal') {
      properties = {
        "Name": {
          "title": [{
            "text": { "content": idea.title }
          }]
        },
        "Tags": {
          "multi_select": idea.categorization.tags.map(tag => ({ "name": tag }))
        }
      };
      content = `# ${idea.title}\n\n${idea.original_content}\n\n## Journal Entry\n- **Category**: ${idea.categorization.category}\n- **Date**: ${new Date().toISOString().split('T')[0]}\n- **Tags**: ${idea.categorization.tags.join(', ')}`;
    }

    // Mock successful creation
    const creationResult = {
      idea_id: idea.idea_id,
      database_type: databaseType,
      database_id: databaseId,
      creation_status: 'success',
      page_id: `mock_page_${Date.now()}_${index}`,
      properties: properties,
      content: content,
      timestamp: new Date().toISOString()
    };

    creationResults.push(creationResult);
    successfulCreations++;

    console.log(`✅ Created ${databaseType} item: ${idea.title}`);

  } catch (error) {
    failedCreations++;
    const errorResult = {
      idea_id: idea.idea_id,
      database_type: idea.categorization.database,
      database_id: idea.categorization.database_id,
      creation_status: 'failed',
      error: error.message,
      timestamp: new Date().toISOString()
    };

    creationResults.push(errorResult);
    console.error(`❌ Failed to create item: ${idea.title} - ${error.message}`);
  }
});

// Calculate database breakdown
const databaseBreakdown = {
  projects: { created: 0, failed: 0 },
  knowledge: { created: 0, failed: 0 },
  journal: { created: 0, failed: 0 }
};

creationResults.forEach(result => {
  if (databaseBreakdown[result.database_type]) {
    if (result.creation_status === 'success') {
      databaseBreakdown[result.database_type].created++;
    } else {
      databaseBreakdown[result.database_type].failed++;
    }
  }
});

// Create comprehensive Phase 2 results
const phase2Results = {
  agent_id: 'notion_direct',
  task_id: phase2Instructions.task_id,
  phase: 'database_creation_complete',
  timestamp: new Date().toISOString(),
  execution_time_ms: Date.now() - new Date().getTime(),
  results: {
    database_items_created: creationResults,
    source_ideas_updated: [], // Not implemented in this test
    summary: {
      total_ideas_processed: totalProcessed,
      successful_creations: successfulCreations,
      failed_creations: failedCreations,
      projects_created: databaseBreakdown.projects.created,
      knowledge_created: databaseBreakdown.knowledge.created,
      journal_created: databaseBreakdown.journal.created,
      source_ideas_completed: 0 // Not implemented in this test
    }
  },
  status: {
    success: failedCreations === 0,
    errors: creationResults.filter(r => r.creation_status === 'failed').map(r => r.error),
    next_phase: failedCreations === 0 ? 'workflow_complete' : 'error_review'
  },
  performance_metrics: {
    database_schemas_fetched: Object.keys(targetDatabases).length,
    api_calls_made: totalProcessed,
    average_creation_time_ms: totalProcessed > 0 ? 100 : 0 // Mock timing
  }
};

// Return results for next node
return {
  json: {
    phase2Results: phase2Results,
    creationResults: creationResults,
    databaseBreakdown: databaseBreakdown,
    summary: {
      total_processed: totalProcessed,
      successful: successfulCreations,
      failed: failedCreations,
      success_rate: totalProcessed > 0 ? (successfulCreations / totalProcessed) * 100 : 0
    },
    output: `Phase 2 Database Creation Complete!\n\n📊 RESULTS SUMMARY:\n- Total Ideas Processed: ${totalProcessed}\n- Successful Creations: ${successfulCreations}\n- Failed Creations: ${failedCreations}\n- Success Rate: ${totalProcessed > 0 ? Math.round((successfulCreations / totalProcessed) * 100) : 0}%\n\n📁 DATABASE BREAKDOWN:\n- Projects: ${databaseBreakdown.projects.created} created, ${databaseBreakdown.projects.failed} failed\n- Knowledge: ${databaseBreakdown.knowledge.created} created, ${databaseBreakdown.knowledge.failed} failed\n- Journal: ${databaseBreakdown.journal.created} created, ${databaseBreakdown.journal.failed} failed\n\n✅ Phase 2 database creation workflow completed successfully!`
  }
};

// Process Direct Database Creation Results
const directCreationOutput = $json;
const phase2Context = $('Parse Phase 2 Instructions').first().json;

// Extract results from Direct Database Creation node
const phase2Results = directCreationOutput.phase2Results;
const creationResults = directCreationOutput.creationResults || [];
const databaseBreakdown = directCreationOutput.databaseBreakdown;
const summary = directCreationOutput.summary;

console.log('Direct Creation Results:', JSON.stringify({
  totalProcessed: summary?.total_processed,
  successful: summary?.successful,
  failed: summary?.failed,
  successRate: summary?.success_rate
}));

// Calculate comprehensive metrics
const totalExecutionTime = Date.now() - new Date($('Setup Phase 2 Context').first().json.phase2Context.startTime).getTime();
const originalIdeasCount = phase2Context.categorized_ideas?.length || 0;

// Create workflow completion summary using actual results
const workflowSummary = {
  phase2_complete: true,
  workflow_complete: phase2Results?.status?.next_phase === 'workflow_complete',
  total_execution_time_ms: totalExecutionTime,
  phase1_results: {
    ideas_categorized: originalIdeasCount,
    categories_assigned: ['projects', 'knowledge', 'journal']
  },
  phase2_results: {
    database_items_created: summary?.successful || 0,
    source_ideas_updated: 0, // Not implemented in test
    creation_success_rate: (summary?.success_rate || 0) / 100 // Convert percentage to decimal
  },
  database_breakdown: databaseBreakdown || {
    projects: { created: 0, failed: 0 },
    knowledge: { created: 0, failed: 0 },
    journal: { created: 0, failed: 0 }
  },
  performance_analysis: {
    avg_time_per_creation: phase2Results?.performance_metrics?.average_creation_time_ms || 0,
    total_api_calls: phase2Results?.performance_metrics?.api_calls_made || 0,
    schemas_fetched: phase2Results?.performance_metrics?.database_schemas_fetched || 0
  }
};

// Create Director context update payload
const directorContextUpdate = {
  context_id: phase2Context.context_id,
  phase: 'workflow_complete',
  agent_response: phase2Results,
  workflow_summary: workflowSummary,
  timestamp: new Date().toISOString()
};

// Final output with corrected data
return [{
  phase2Complete: true,
  workflowResults: {
    phase1_categorization: {
      ideas_processed: originalIdeasCount,
      categorization_complete: true
    },
    phase2_creation: {
      items_created: summary?.successful || 0,
      success_rate: (summary?.success_rate || 0) / 100,
      database_breakdown: databaseBreakdown || {
        projects: { created: 0, failed: 0 },
        knowledge: { created: 0, failed: 0 },
        journal: { created: 0, failed: 0 }
      }
    },
    overall_success: (summary?.failed || 0) === 0 && (summary?.successful || 0) > 0,
    total_time_ms: totalExecutionTime
  },
  directorContextUpdate,
  phase2Results,
  rawAgentOutput: directCreationOutput.output || 'Direct database creation completed',
  debugInfo: {
    original_ideas_count: originalIdeasCount,
    context_id: phase2Context.context_id,
    task_id: phase2Context.task_id,
    databases_targeted: Object.keys(phase2Context.target_databases || {}),
    direct_creation_summary: summary,
    creation_results_count: creationResults.length
  }
}];
